nta.declaration:
const int num_floors = 4;                 // Number of floors
typedef int[0,num_floors-1] f_id;        // Floor ids
typedef int Direction; // -1 for down, 0 for idle, 1 for up

const int DOOR_TIMEOUT = 5;
const int FLOOR_TRAVEL_TIME = 3;

// Holds the data for a floor call, which floor it was called from and which direction it needs to go.
// Modified by floor panel, read by servicequeue once message is posted to floorCall channel
typedef struct {
    int floor_called_from;
    Direction direction; 
} FloorCall;
FloorCall floorCall; // actual global instance which gets modified.

// Encapsulates up/down buttons at each floor
typedef struct {
    bool up;
    bool down;
} FloorButton;
FloorButton floorButtons[num_floors];

typedef struct {
    int selected_floor;
} GotoFloor;
GotoFloor gotoFloor;

typedef struct {
    int display_floor;
    Direction direction;
} DisplayData;

DisplayData floorDisplay[num_floors];
DisplayData elevatorDisplay;


// elevator state
int current_floor     = 0;
int target_floor      = 0;
Direction target_direction = 0;
Direction currentDirection = 0;


bool hasElevatorArrived(int current, int target) {
    if (current == target) {return true;}
    return false;
}


// passive data structures
bool overloaded= false;
bool motion_detected = false;
bool inMaintenance = false;


bool elevatorButtons[num_floors] = {false, false, false, false}; // if elevator is called to that floor
bool floorDoors[num_floors] = {false, false, false, false}; // if elevator at that floor

bool allDoorsClosed() {
    int i;
    for (i = 0; i < num_floors; i++) {
        if (floorDoors[i]) {return false;}
    }
    return true;
}

// channels
chan floorCallChannel[num_floors];
chan gotoFloorChannel;
chan serviceQueueProcessed;
broadcast chan elevatorArrivedChannel;

chan doorCloseChannel[num_floors];

template.declaration:
typedef struct {
    int floorNumber;
    Direction direction;
    bool isElevatorCall;
} Request;

Request queue[10]; // Assuming a maximum of 10 requests
int queueSize = 0;


void appendElevatorRequest(GotoFloor& g) {

    queue[queueSize].floorNumber = g.selected_floor;
	queue[queueSize].direction = 0; // Default direction for elevator calls
	queue[queueSize].isElevatorCall = true;
	queueSize++;
}

void appendFloorRequest(FloorCall& f) {

    queue[queueSize].floorNumber = f.floor_called_from;
    queue[queueSize].direction = f.direction;
    queue[queueSize].isElevatorCall = false;
    queueSize++;
}


void processQueue() {
    int best = 0;
    int i;
    // 1) Look for a request in-direction and ahead
    for (i = 0; i < queueSize; i++) {
        if (currentDirection == 1
            && queue[i].floorNumber > current_floor) {
            best = i; 
        }
        if (currentDirection == -1
            && queue[i].floorNumber < current_floor) {
            best = i;
        }
    }
    // 2) Set globals from chosen entry
    target_floor = queue[best].floorNumber;
    if (target_floor > current_floor)      target_direction = 1;
    else if (target_floor < current_floor) target_direction = -1;
    else                                    target_direction = 0;

    currentDirection = target_direction;
    // 3) Remove chosen entry (shift left)
    for (i = best; i < queueSize - 1; i++) {
        queue[i] = queue[i + 1];
    }
    queueSize--;
}

