// Place template instantiations here.

floor_panel_0 = FloorPanel(0);
floor_panel_1 = FloorPanel(1);
floor_panel_2 = FloorPanel(2);
floor_panel_3 = FloorPanel(3);
elevator_panel = ElevatorPanel();

service_queue = ServiceQueue();
elevator_manager = ElevatorManager();

door_motor_controller = DoorMotorController();

user = User();

// List one or more processes to be composed into a system.
//system floor_panel_0, service_queue, user, elevator_panel, elevator_manager;
system user,floor_panel_0,floor_panel_1,floor_panel_2, floor_panel_3, service_queue, elevator_panel, elevator_manager, door_motor_controller;
